  6→/// Execute result
  7→#[derive(Debug, Clone, PartialEq, Eq)]
  8→pub enum ExecuteResult {
  9→    /// Instruction executed successfully
 10→    Ok,
 11→    /// CPU halted
 12→    Halted,
 13→    /// Invalid instruction
 14→    InvalidInstruction(u8),
 15→    /// Memory access error
 16→    MemoryError(u32),
 17→}
 18→
 19→/// COR24 instruction executor
 20→#[derive(Clone)]
 21→pub struct Executor {
 22→    decode_rom: DecodeRom,
 23→}
 24→
 25→impl Default for Executor {
 26→    fn default() -> Self {
 27→        Self::new()
 28→    }
 29→}
 30→
 31→impl Executor {
 32→    pub fn new() -> Self {
 33→        Self {
 34→            decode_rom: DecodeRom::new(),
 35→        }
 36→    }
 37→
 38→    /// Execute a single instruction
 39→    pub fn step(&self, cpu: &mut CpuState) -> ExecuteResult {
 40→        if cpu.halted {
 41→            return ExecuteResult::Halted;
 42→        }
 43→
 44→        // Check for pending interrupt at instruction boundary
 45→        // Hardware: automatic jal r7,(r6) when uart_rxrdy && ienab && !intis
 46→        if cpu.interrupt_pending() {
 47→            cpu.intis = true;
 48→            let target = cpu.get_reg(6); // r6 = interrupt vector
 49→            cpu.set_reg(7, cpu.pc); // r7 = return address (current PC)
 50→            cpu.pc = target;
 51→            cpu.cycles += 1;
 52→            cpu.instructions += 1;
 53→            return ExecuteResult::Ok;
 54→        }
 55→
 56→        // Fetch instruction byte
 57→        let inst_byte = cpu.read_byte(cpu.pc);
 58→
 59→        // Check for HALT (using 0x00 at address 0 as halt)
 60→        if inst_byte == 0x00 && cpu.pc == 0 {
 61→            cpu.halted = true;
 62→            return ExecuteResult::Halted;
 63→        }
 64→
 65→        // NOP: 0xFF is not in the decode ROM but is a valid no-op
 66→        if inst_byte == 0xFF {
 67→            cpu.pc = CpuState::mask_24(cpu.pc.wrapping_add(1));
 68→            cpu.instructions += 1;
 69→            return ExecuteResult::Ok;
 70→        }
 71→
 72→        // Decode instruction
 73→        let decoded_value = self.decode_rom.decode(inst_byte);
 74→        if decoded_value == 0xFFF {
 75→            return ExecuteResult::InvalidInstruction(inst_byte);
 76→        }
 77→
 78→        let inst = DecodedInstruction::from_decoded(decoded_value);
 79→        let format = inst.opcode.format();
 80→
 81→        // Fetch additional bytes based on format
 82→        let imm8 = match format {
 83→            InstructionFormat::TwoBytes | InstructionFormat::FourBytes => {
 84→                cpu.read_byte(cpu.pc.wrapping_add(1))
 85→            }
 86→            _ => 0,
 87→        };
 88→
 89→        let imm24 = match format {
 90→            InstructionFormat::FourBytes => {
 91→                let b0 = cpu.read_byte(cpu.pc.wrapping_add(1)) as u32;
 92→                let b1 = cpu.read_byte(cpu.pc.wrapping_add(2)) as u32;
 93→                let b2 = cpu.read_byte(cpu.pc.wrapping_add(3)) as u32;
 94→                b0 | (b1 << 8) | (b2 << 16)
 95→            }
 96→            _ => 0,
 97→        };
 98→
 99→        // Calculate next PC
100→        let inst_size: u32 = match format {
101→            InstructionFormat::SingleByte => 1,
102→            InstructionFormat::TwoBytes => 2,
103→            InstructionFormat::FourBytes => 4,
104→        };
105→        let next_pc = CpuState::mask_24(cpu.pc.wrapping_add(inst_size));
106→
107→        // Capture pre-execution state for trace
108→        let trace_pc = cpu.pc;
109→        let trace_regs_before = cpu.registers;
110→        let trace_c_before = cpu.c;
111→        let trace_sp_before = cpu.get_reg(4);
112→        let trace_instruction_num = cpu.instructions;
113→        let mut halted_by_self_branch = false;
114→
115→        // Execute instruction
116→        match inst.opcode {
117→            Opcode::AddReg => {
118→                // add ra,rb
119→                let ra_val = cpu.get_reg(inst.ra);
120→                let rb_val = cpu.get_reg(inst.rb);
121→                let result = CpuState::mask_24(ra_val.wrapping_add(rb_val));
122→                cpu.set_reg(inst.ra, result);
123→                cpu.pc = next_pc;
124→            }
125→
126→            Opcode::AddImm => {
127→                // add ra,dd
128→                let ra_val = cpu.get_reg(inst.ra);
129→                let imm = CpuState::sign_extend_8(imm8);
130→                let result = CpuState::mask_24(ra_val.wrapping_add(imm));
131→                cpu.set_reg(inst.ra, result);
132→                cpu.pc = next_pc;
133→            }
134→
135→            Opcode::And => {
136→                // and ra,rb
137→                let ra_val = cpu.get_reg(inst.ra);
138→                let rb_val = cpu.get_reg(inst.rb);
139→                cpu.set_reg(inst.ra, ra_val & rb_val);
140→                cpu.pc = next_pc;
141→            }
142→
143→            Opcode::Bra => {
144→                // bra dd (always branch)
145→                // Hardware pipeline: PC is 2 ahead of next instruction at execute time
146→                // So branch base = instruction_addr + 4 = next_pc + 2
147→                let offset = CpuState::sign_extend_8(imm8);
148→                let branch_base = next_pc.wrapping_add(2);
149→                let target = CpuState::mask_24(branch_base.wrapping_add(offset));
150→                // Detect self-branch (halt: bra halt) as halt condition
151→                let instruction_addr = CpuState::mask_24(next_pc.wrapping_sub(2));
152→                if target == instruction_addr {
153→                    cpu.pc = instruction_addr;
154→                    cpu.halted = true;
155→                    halted_by_self_branch = true;
156→                } else {
157→                    cpu.pc = target;
158→                }
159→            }
160→
161→            Opcode::Brf => {
162→                // brf dd (branch if false)
163→                if !cpu.c {
164→                    let offset = CpuState::sign_extend_8(imm8);
165→                    let branch_base = next_pc.wrapping_add(2);
166→                    cpu.pc = CpuState::mask_24(branch_base.wrapping_add(offset));
167→                } else {
168→                    cpu.pc = next_pc;
169→                }
170→            }
171→
172→            Opcode::Brt => {
173→                // brt dd (branch if true)
174→                if cpu.c {
175→                    let offset = CpuState::sign_extend_8(imm8);
176→                    let branch_base = next_pc.wrapping_add(2);
177→                    cpu.pc = CpuState::mask_24(branch_base.wrapping_add(offset));
178→                } else {
179→                    cpu.pc = next_pc;
180→                }
181→            }
182→
183→            Opcode::Ceq => {
184→                // ceq ra,rb (compare equal)
185→                let ra_val = cpu.get_reg(inst.ra);
186→                let rb_val = cpu.get_reg(inst.rb);
187→                cpu.c = ra_val == rb_val;
188→                cpu.pc = next_pc;
189→            }
190→
191→            Opcode::Cls => {
192→                // cls ra,rb (compare less signed)
193→                let ra_val = cpu.get_reg(inst.ra) as i32;
194→                let rb_val = cpu.get_reg(inst.rb) as i32;
195→                // Sign extend from 24-bit
196→                let ra_signed = if ra_val & 0x800000 != 0 {
197→                    ra_val | 0xFF000000u32 as i32
198→                } else {
199→                    ra_val
200→                };
201→                let rb_signed = if rb_val & 0x800000 != 0 {
202→                    rb_val | 0xFF000000u32 as i32
203→                } else {
204→                    rb_val
205→                };
206→                cpu.c = ra_signed < rb_signed;
207→                cpu.pc = next_pc;
208→            }
209→
210→            Opcode::Clu => {
211→                // clu ra,rb (compare less unsigned)
212→                let ra_val = cpu.get_reg(inst.ra);
213→                let rb_val = cpu.get_reg(inst.rb);
214→                cpu.c = ra_val < rb_val;
215→                cpu.pc = next_pc;
216→            }
217→
218→            Opcode::Jal => {
219→                // jal ra,(rb) - jump and link
220→                let target = cpu.get_reg(inst.rb);
221→                cpu.set_reg(inst.ra, next_pc);
222→                cpu.pc = target;
223→            }
224→
225→            Opcode::Jmp => {
226→                // jmp (ra)
227→                let target = cpu.get_reg(inst.ra);
228→                // jmp (r7) clears interrupt-in-service flag (hardware: &racode)
229→                if inst.ra == 7 {
230→                    cpu.intis = false;
231→                }
232→                cpu.pc = target;
233→            }
234→
235→            Opcode::La => {
236→                // la ra,dddddd
237→                if inst.ra == 7 {
238→                    // jmp dddddd (absolute jump)
239→                    cpu.pc = imm24;
240→                } else {
241→                    cpu.set_reg(inst.ra, imm24);
242→                    cpu.pc = next_pc;
243→                }
244→            }
245→
246→            Opcode::Lb => {
247→                // lb ra,dd(rb) - load byte signed
248→                let base = cpu.get_reg(inst.rb);
249→                let offset = CpuState::sign_extend_8(imm8);
250→                let addr = CpuState::mask_24(base.wrapping_add(offset));
251→                let value = cpu.read_byte_exec(addr);
252→                cpu.set_reg(inst.ra, CpuState::sign_extend_8(value));
253→                cpu.pc = next_pc;
254→            }
255→
256→            Opcode::Lbu => {
257→                // lbu ra,dd(rb) - load byte unsigned
258→                let base = cpu.get_reg(inst.rb);
259→                let offset = CpuState::sign_extend_8(imm8);
260→                let addr = CpuState::mask_24(base.wrapping_add(offset));
261→                let value = cpu.read_byte_exec(addr);
262→                cpu.set_reg(inst.ra, value as u32);
263→                cpu.pc = next_pc;
264→            }
265→
266→            Opcode::Lc => {
267→                // lc ra,dd - load constant signed
268→                cpu.set_reg(inst.ra, CpuState::sign_extend_8(imm8));
269→                cpu.pc = next_pc;
270→            }
271→
272→            Opcode::Lcu => {
273→                // lcu ra,dd - load constant unsigned
274→                cpu.set_reg(inst.ra, imm8 as u32);
275→                cpu.pc = next_pc;
276→            }
277→
278→            Opcode::Lw => {
279→                // lw ra,dd(rb) - load word
280→                let base = cpu.get_reg(inst.rb);
281→                let offset = CpuState::sign_extend_8(imm8);
282→                let addr = CpuState::mask_24(base.wrapping_add(offset));
283→                let value = cpu.read_word(addr);
284→                cpu.set_reg(inst.ra, value);
285→                cpu.pc = next_pc;
286→            }
287→
288→            Opcode::Mov => {
289→                // mov ra,rb or mov ra,c
290→                if inst.rb == 5 {
291→                    // mov ra,c
292→                    cpu.set_reg(inst.ra, if cpu.c { 1 } else { 0 });
293→                } else {
294→                    cpu.set_reg(inst.ra, cpu.get_reg(inst.rb));
295→                }
296→                cpu.pc = next_pc;
297→            }
298→
299→            Opcode::Mul => {
300→                // mul ra,rb
301→                let ra_val = cpu.get_reg(inst.ra);
302→                let rb_val = cpu.get_reg(inst.rb);
303→                let result = CpuState::mask_24(ra_val.wrapping_mul(rb_val));
304→                cpu.set_reg(inst.ra, result);
305→                cpu.pc = next_pc;
306→            }
307→
308→            Opcode::Or => {
309→                // or ra,rb
310→                let ra_val = cpu.get_reg(inst.ra);
311→                let rb_val = cpu.get_reg(inst.rb);
312→                cpu.set_reg(inst.ra, ra_val | rb_val);
313→                cpu.pc = next_pc;
314→            }
315→
316→            Opcode::Pop => {
317→                // pop ra - load from stack, increment sp
318→                let sp = cpu.get_reg(4);
319→                let value = cpu.read_word(sp);
320→                cpu.set_reg(inst.ra, value);
321→                cpu.set_reg(4, CpuState::mask_24(sp.wrapping_add(3)));
322→                cpu.pc = next_pc;
323→            }
324→
325→            Opcode::Push => {
326→                // push ra - decrement sp, store to stack
327→                let sp = cpu.get_reg(4);
328→                let new_sp = CpuState::mask_24(sp.wrapping_sub(3));
329→                cpu.set_reg(4, new_sp);
330→                let value = cpu.get_reg(inst.ra);
331→                cpu.write_word(new_sp, value);
332→                cpu.pc = next_pc;
333→            }
334→
335→            Opcode::Sb => {
336→                // sb ra,dd(rb) - store byte
337→                let base = cpu.get_reg(inst.rb);
338→                let offset = CpuState::sign_extend_8(imm8);
339→                let addr = CpuState::mask_24(base.wrapping_add(offset));
340→                let value = cpu.get_reg(inst.ra) as u8;
341→                cpu.write_byte(addr, value);
342→                cpu.pc = next_pc;
343→            }
344→
345→            Opcode::Shl => {
346→                // shl ra,rb - shift left
347→                let ra_val = cpu.get_reg(inst.ra);
348→                let shift = cpu.get_reg(inst.rb) & 0x1F;
349→                let result = CpuState::mask_24(ra_val << shift);
350→                cpu.set_reg(inst.ra, result);
351→                cpu.pc = next_pc;
352→            }
353→
354→            Opcode::Sra => {
355→                // sra ra,rb - shift right arithmetic
356→                let ra_val = cpu.get_reg(inst.ra);
357→                let shift = cpu.get_reg(inst.rb) & 0x1F;
358→                // Sign extend for arithmetic shift
359→                let signed_val = if ra_val & 0x800000 != 0 {
360→                    ra_val | 0xFF000000
361→                } else {
362→                    ra_val
363→                };
364→                let result = CpuState::mask_24((signed_val as i32 >> shift) as u32);
365→                cpu.set_reg(inst.ra, result);
366→                cpu.pc = next_pc;
367→            }
368→
369→            Opcode::Srl => {
370→                // srl ra,rb - shift right logical
371→                let ra_val = cpu.get_reg(inst.ra);
372→                let shift = cpu.get_reg(inst.rb) & 0x1F;
373→                let result = ra_val >> shift;
374→                cpu.set_reg(inst.ra, result);
375→                cpu.pc = next_pc;
376→            }
377→
378→            Opcode::Sub => {
379→                // sub ra,rb
380→                let ra_val = cpu.get_reg(inst.ra);
381→                let rb_val = cpu.get_reg(inst.rb);
382→                let result = CpuState::mask_24(ra_val.wrapping_sub(rb_val));
383→                cpu.set_reg(inst.ra, result);
384→                cpu.pc = next_pc;
385→            }
386→
387→            Opcode::SubSp => {
388→                // sub sp,dddddd
389→                let sp = cpu.get_reg(4);
390→                let result = CpuState::mask_24(sp.wrapping_sub(imm24));
391→                cpu.set_reg(4, result);
392→                cpu.pc = next_pc;
393→            }
394→
395→            Opcode::Sw => {
396→                // sw ra,dd(rb) - store word
397→                let base = cpu.get_reg(inst.rb);
398→                let offset = CpuState::sign_extend_8(imm8);
399→                let addr = CpuState::mask_24(base.wrapping_add(offset));
400→                let value = cpu.get_reg(inst.ra);
401→                cpu.write_word(addr, value);
402→                cpu.pc = next_pc;
403→            }
404→
405→            Opcode::Sxt => {
406→                // sxt ra,rb - sign extend byte
407→                let rb_val = cpu.get_reg(inst.rb);
408→                cpu.set_reg(inst.ra, CpuState::sign_extend_8(rb_val as u8));
409→                cpu.pc = next_pc;
410→            }
411→
412→            Opcode::Xor => {
413→                // xor ra,rb
414→                let ra_val = cpu.get_reg(inst.ra);
415→                let rb_val = cpu.get_reg(inst.rb);
416→                cpu.set_reg(inst.ra, ra_val ^ rb_val);
417→                cpu.pc = next_pc;
418→            }
419→
420→            Opcode::Zxt => {
421→                // zxt ra,rb - zero extend byte
422→                let rb_val = cpu.get_reg(inst.rb);
423→                cpu.set_reg(inst.ra, rb_val & 0xFF);
424→                cpu.pc = next_pc;
425→            }
426→
427→            Opcode::Invalid => {
428→                return ExecuteResult::InvalidInstruction(inst_byte);
429→            }
430→        }
431→
432→        cpu.cycles += 1;
433→        cpu.instructions += 1;
434→        cpu.uart_tick();
435→
436→        // Record trace entry
437→        cpu.trace.push(TraceEntry {
438→            pc: trace_pc,
439→            opcode: inst.opcode,
440→            ra: inst.ra,
441→            rb: inst.rb,
442→            size: inst_size as u8,
443→            imm8,
444→            imm24,
445→            regs_before: trace_regs_before,
